import React, { useContext, useRef, useEffect, useState } from 'react';
import { GlobalAudioContext } from '../GlobalAudioContext';
import './panel.css';

const Panel = () => {
  const { audioSettings, setAudioSettings } = useContext(GlobalAudioContext);
  const audioRef = useRef(null);
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    if (audioSettings.audioFileUrl && audioRef.current) {
      audioRef.current.src = audioSettings.audioFileUrl;
      audioRef.current.onloadedmetadata = () => {
        setAudioSettings(prev => ({ ...prev, duration: audioRef.current.duration }));
      };
    }
  }, [audioSettings.audioFileUrl]);

  const handlePlay = () => {
    if (audioRef.current) {
      audioRef.current.play();
      setAudioSettings(prev => ({ ...prev, isPlaying: true }));
    }
  };

  const handleStop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      setAudioSettings(prev => ({ ...prev, isPlaying: false, currentTime: 0 }));
    }
  };

  const handleVolumeChange = (e) => {
    const volume = parseFloat(e.target.value);
    setAudioSettings(prev => ({ ...prev, volume }));
    if (audioRef.current) {
      audioRef.current.volume = volume;
    }
  };

  const handlePanningChange = (e) => {
    const panning = parseFloat(e.target.value);
    setAudioSettings(prev => ({ ...prev, panning }));
    // 패닝 적용 로직 추가
  };

  const handleTimelineChange = (e) => {
    const currentTime = parseFloat(e.target.value);
    setAudioSettings(prev => ({ ...prev, currentTime }));
    if (audioRef.current) {
      audioRef.current.currentTime = currentTime;
    }
  };

  const handleEffectCheckboxChange = (effectName, checked) => {
    setAudioSettings(prev => ({ ...prev, [`${effectName}Enabled`]: checked }));
  };

  return (
    <div className={`sliding-panel ${isOpen ? 'open' : ''}`}>
      <button className="toggle-button" onClick={() => setIsOpen(!isOpen)}>
        {isOpen ? 'Close Panel' : 'Open Panel'}
      </button>
      <div className="panel-content">
        <div className="panel-section">
          <label>오디오 입력 선택:</label>
          <select
            value={audioSettings.inputSource}
            onChange={(e) => setAudioSettings(prev => ({ ...prev, inputSource: e.target.value }))}
          >
            <option value="laptop">노트북 마이크</option>
            <option value="usb">USB 입력</option>
            <option value="audioFile">오디오 파일</option>
          </select>
        </div>
        {audioSettings.inputSource === "audioFile" && (
          <div className="panel-section">
            <label>오디오 파일 업로드 (MP3, WAV):</label>
            <input
              type="file"
              accept="audio/mpeg, audio/wav"
              onChange={(e) => {
                if (e.target.files.length > 0) {
                  const file = e.target.files[0];
                  const url = URL.createObjectURL(file);
                  setAudioSettings(prev => ({ ...prev, audioFileUrl: url }));
                }
              }}
            />
          </div>
        )}
        <div className="panel-section">
          <button onClick={handlePlay}>Play</button>
          <button onClick={handleStop}>Stop</button>
        </div>
        <div className="panel-section">
          <label>타임라인:</label>
          <input
            type="range"
            min="0"
            max={audioSettings.duration}
            step="0.1"
            value={audioSettings.currentTime}
            onChange={handleTimelineChange}
          />
          <span>{audioSettings.currentTime.toFixed(1)} s / {audioSettings.duration.toFixed(1)} s</span>
        </div>
        <div className="panel-section">
          <label>볼륨:</label>
          <input
            type="range"
            min="0"
            max="1"
            step="0.01"
            value={audioSettings.volume}
            onChange={handleVolumeChange}
          />
          <span>{(audioSettings.volume * 100).toFixed(0)}%</span>
        </div>
        <div className="panel-section">
          <label>패닝:</label>
          <input
            type="range"
            min="-1"
            max="1"
            step="0.01"
            value={audioSettings.panning}
            onChange={handlePanningChange}
          />
          <span>{audioSettings.panning}</span>
        </div>
        <div className="panel-section">
          <h3>적용 효과 (컴포넌트 페이지 별)</h3>
          <div className="checkbox-group">
            <label>
              <input
                type="checkbox"
                checked={audioSettings.compEnabled}
                onChange={(e) => handleEffectCheckboxChange("comp", e.target.checked)}
              />
              컴프레서 적용
            </label>
            <label>
              <input
                type="checkbox"
                checked={audioSettings.reverbEnabled}
                onChange={(e) => handleEffectCheckboxChange("reverb", e.target.checked)}
              />
              리버브 적용
            </label>
            <label>
              <input
                type="checkbox"
                checked={audioSettings.eqEnabled}
                onChange={(e) => handleEffectCheckboxChange("eq", e.target.checked)}
              />
              EQ 적용
            </label>
          </div>
        </div>
      </div>
      <audio ref={audioRef} />
    </div>
  );
};

export default Panel;