import React, { useState, useEffect, useRef } from 'react';
import './start.css';

/* 예시 이미지들 */
import carousel1 from '../../assets/background1.webp';
import carousel2 from '../../assets/image2.png';
import backgroundImg from '../../assets/image3.jpg';
import featureImg from '../../assets/img1.png';
import myPhoto from '../../assets/me.jpeg'; // PNG 파일 (윤곽선 제거)

/* 캐러셀에 사용할 이미지 목록 */
const carouselImages = [carousel1, carousel2, backgroundImg, carousel2];

const Start = () => {
  /* ---------------------------------------
     섹션 페이드 인 (Intersection Observer)
  --------------------------------------- */
  const sectionsRef = useRef([]);
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('visible');
          }
        });
      },
      { threshold: 0.05 } // 낮춰서 부드럽게
    );

    sectionsRef.current.forEach((sec) => {
      if (sec) observer.observe(sec);
    });

    return () => {
      sectionsRef.current.forEach((sec) => {
        if (sec) observer.unobserve(sec);
      });
    };
  }, []);

  /* ---------------------------------------
     1) 첫 번째 섹션: 간단 캐러셀 (4초 간격)
  --------------------------------------- */
  const [currentSlide, setCurrentSlide] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % carouselImages.length);
    }, 4000);
    return () => clearInterval(intervalId);
  }, []);

  const goPrev = () => {
    setCurrentSlide((prev) => (prev - 1 + carouselImages.length) % carouselImages.length);
  };
  const goNext = () => {
    setCurrentSlide((prev) => (prev + 1) % carouselImages.length);
  };

  /* ---------------------------------------
     2) 두 번째 섹션: 이미지 + 텍스트
  --------------------------------------- */

  /* ---------------------------------------
     3) 세 번째 섹션: 4열 2행 카드 (8개)
  --------------------------------------- */
  // 카드 정보 (8개)
  const cardsData = [
    { title: 'Equalizer / 이퀄라이져', content: 'Equalizer system is a device or software that adjusts the frequency of an acoustic signal to optimize sound quality.' },
    { title: 'Reverb / 리버브', content: 'Reverb is an effect that reflects sound to add a natural sense of space and depth.' },
    { title: 'Compressor / 컴프레셔', content: 'A compressor is an effect that adjusts the dynamic range of a sound to maintain a balanced loudness.' },
    { title: 'Distortion / 디스토션', content: 'Distortion is an effect that crushes or amplifies sound to create a harsh, strong tone.' },
    { title: 'Dynamic / 다이나믹', content: 'Dynamics is the ability to adjust the loudness of sounds to make music more expressive.' },
    { title: 'Effects / 이펙터', content: 'Effects are the ability to add different effects to sounds to change their tone and mood.' },
  ];

  /* ---------------------------------------
     4) 네 번째 섹션: 폼 -> MongoDB
  --------------------------------------- */
  const [formName, setFormName] = useState('');
  const [formEmail, setFormEmail] = useState('');
  const [formJobMajor, setFormJobMajor] = useState('');
  const [formRequest, setFormRequest] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    // POST 요청으로 MongoDB에 저장
    try {
      const response = await fetch('http://localhost:4000/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formName,
          email: formEmail,
          jobMajor: formJobMajor,
          request: formRequest,
        }),
      });
      if (!response.ok) {
        throw new Error('Failed to submit');
      }
      alert('요청사항이 반영될 수 있게 노력하겠습니다. Thank You For Your Request!');
      // 폼 초기화
      setFormName('');
      setFormEmail('');
      setFormJobMajor('');
      setFormRequest('');
    } catch (err) {
      console.error(err);
      alert('Error submitting form.');
    }
  };

  return (
    <div className="start-container">
      {/* =========================
          첫 번째 섹션: 캐러셀
      ========================== */}
      <section
        className="start-section start-intro"
        ref={(el) => (sectionsRef.current[0] = el)}
      >
        {/* 슬라이드들 */}
        <div className="start-intro-carousel-wrapper">
          {carouselImages.map((img, i) => (
            <div
              key={i}
              className={`start-intro-slide ${i === currentSlide ? 'active' : ''}`}
              style={{ backgroundImage: `url(${img})` }}
            />
          ))}
          {/* 좌우 버튼 */}
          <button className="start-intro-arrow left" onClick={goPrev}>
            &lt;
          </button>
          <button className="start-intro-arrow right" onClick={goNext}>
            &gt;
          </button>
        </div>
        {/* 고정 타이틀 */}
        <div className="start-intro-content">
          <h1>Welcome to Plug-In Site</h1>
          <p className="start-subtitle">Experience the Free Audio Plugin_developed by IHS</p>
        </div>
      </section>

      {/* =========================
          두 번째 섹션: 이미지+텍스트
      ========================== */}
      <section
        className="start-section start-features"
        ref={(el) => (sectionsRef.current[1] = el)}
      >
        <div className="start-features-image-container">
          <img src={featureImg} alt="Feature" />
        </div>
        <div className="start-features-text-container">
          <h2>Our Service / 서비스 안내</h2>
          <p>
          악기 및 음향과 관련된 플러그인을 활용하기 위해 프로그램을 다운받고, 유료로 결제하는 것이 불편하지는 않으셨나요? 웹에서 무료로 이용 가능한 플러그인을 사용해주시고, 언제든지 개선사항을 알려주시면 더 다양하고 뛰어난 플러그인들이 개발될 수 있습니다. 당신의 오디오 작업을 돕는, 성장하는 사이트가 되겠습니다!
          </p>
          <p>
          Have you ever paid to use plug-ins for instruments and sounds? Try using plugins that are available for free on the web. Let us know what you think and help us develop more and better plugins. We want to be the site that helps you work with audio!
          </p>
        </div>
      </section>

      {/* =========================
          세 번째 섹션: 카드 4열 2행 (8개)
      ========================== */}
      <section
        className="start-section start-cards"
        ref={(el) => (sectionsRef.current[2] = el)}
      >
        <h2 style={{ position: 'absolute', top: '30px', fontSize: '2rem' }}>
            Available plugins / 이용 가능한 플러그인
        </h2>
        <div className="start-cards-grid">
          {cardsData.map((card, index) => (
            <div className="start-card" key={index}>
              <div className="start-tools">
                <div className="start-circle">
                  <span className="start-red box"></span>
                </div>
                <div className="start-circle">
                  <span className="start-yellow box"></span>
                </div>
                <div className="start-circle">
                  <span className="start-green box"></span>
                </div>
              </div>
              <div className="start-card__content">
                <p className="start-title">{card.title}</p>
                <hr />
                <p className="start-content">{card.content}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* =========================
          네 번째 섹션: MongoDB 폼
      ========================== */}
      <section
        className="start-section start-contact"
        ref={(el) => (sectionsRef.current[3] = el)}
      >
        <div className="start-contact-form">
          <h3>Contact Us</h3>
          <form onSubmit={handleSubmit}>
            <label htmlFor="name">Name / 이름</label>
            <input
              type="text"
              id="name"
              name="name"
              value={formName}
              onChange={(e) => setFormName(e.target.value)}
            />

            <label htmlFor="email">Email / 이메일</label>
            <input
              type="email"
              id="email"
              name="email"
              value={formEmail}
              onChange={(e) => setFormEmail(e.target.value)}
            />

            <label htmlFor="jobMajor">Purpose of Using Plug-in / 플러그인을 이용하시는 목적</label>
            <input
              type="text"
              id="jobMajor"
              name="jobMajor"
              value={formJobMajor}
              onChange={(e) => setFormJobMajor(e.target.value)}
            />

            <label htmlFor="request">Your Request / 요청사항</label>
            <textarea
              id="request"
              name="request"
              value={formRequest}
              onChange={(e) => setFormRequest(e.target.value)}
            />

            <button type="submit">Submit / 제출하기</button>
          </form>
        </div>

        <div className="start-image-container">
          <img src={myPhoto} alt="My Photo" />
          <div className="start-info">
            <h3>About Me</h3>
            <p>
            음향과 컴퓨터에 관심있는 평범한 한국 대학생. ISTJ다운 논리주의자의 삶을 살아가고 있다.
            </p>
            <p>
            An ordinary Korean college student interested in sound and computer. I live the life of an ISTJ logician.
            </p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Start;
