import React, { createContext, useState, useEffect } from 'react';

export const GlobalAudioContext = createContext();

export const GlobalAudioProvider = ({ children }) => {
  const [audioSettings, setAudioSettings] = useState({
    inputSource: 'laptop', // "laptop", "usb", "audioFile"
    volume: 1,
    panning: 0,
    compEnabled: false,
    reverbEnabled: false,
    eqEnabled: false,
    audioFileUrl: null,
    isPlaying: false,
    currentTime: 0,
    duration: 0,
  });

  useEffect(() => {
    // 오디오 재생 상태를 관리하는 로직 추가
    if (audioSettings.isPlaying) {
      // 재생 로직
    } else {
      // 정지 로직
    }
  }, [audioSettings.isPlaying]);

  return (
    <GlobalAudioContext.Provider value={{ audioSettings, setAudioSettings }}>
      {children}
    </GlobalAudioContext.Provider>
  );
};