import React, { useEffect, useRef, useState } from "react";
import * as Tone from "tone";
import "./comp.css";

// 초기 컴프레서 파라미터
const DEFAULT_PARAMS = {
  attack: 20,
  hold: 50,
  release: 100,
  ratio: 2.0,
  threshold: -24,
  knee: 6,
  gain: 0,
  mix: 100,
};

function dbToGain(db) {
  return Math.pow(10, db / 20);
}

function bufferToWave(audioBuffer) {
  // ... (기존 코드 동일)
}

/** 예시 프리셋들 */
const COMP_PRESETS = {
  "Flat (No Compression)": {
    attack: 20,
    hold: 50,
    release: 100,
    ratio: 1.1,
    threshold: 0,
    knee: 0,
    gain: 0,
    mix: 100,
  },
  "Vocal": {
    attack: 10,
    hold: 50,
    release: 120,
    ratio: 3.0,
    threshold: -18,
    knee: 2,
    gain: 2,
    mix: 100,
  },
  "Drum": {
    attack: 5,
    hold: 30,
    release: 80,
    ratio: 6.0,
    threshold: -10,
    knee: 0,
    gain: 4,
    mix: 100,
  },
  "Acoustic": {
    attack: 20,
    hold: 100,
    release: 200,
    ratio: 2.0,
    threshold: -24,
    knee: 4,
    gain: 3,
    mix: 80,
  },
  "Aggressive Limiting": {
    attack: 1,
    hold: 20,
    release: 100,
    ratio: 10.0,
    threshold: -8,
    knee: 0,
    gain: 6,
    mix: 100,
  },
};

const Comp = () => {
  // 컴프레셔 파라미터를 localStorage에서 불러오거나 기본값 사용
  const initialSettings =
    JSON.parse(localStorage.getItem("compressorSettings") || "null") ||
    DEFAULT_PARAMS;
  const [attack, setAttack] = useState(initialSettings.attack);
  const [hold, setHold] = useState(initialSettings.hold);
  const [release, setRelease] = useState(initialSettings.release);
  const [ratio, setRatio] = useState(initialSettings.ratio);
  const [threshold, setThreshold] = useState(initialSettings.threshold);
  const [knee, setKnee] = useState(initialSettings.knee);
  const [gain, setGain] = useState(initialSettings.gain);
  const [mix, setMix] = useState(initialSettings.mix);

  // compressor 설정이 변경될 때마다 localStorage에 저장
  useEffect(() => {
    const settings = { attack, hold, release, ratio, threshold, knee, gain, mix };
    localStorage.setItem("compressorSettings", JSON.stringify(settings));
  }, [attack, hold, release, ratio, threshold, knee, gain, mix]);

  // 오디오 입력 소스 및 파일 관련
  const [inputSource, setInputSource] = useState("audioFile");
  const [audioFile, setAudioFile] = useState(null);

  // 재생 상태 및 타임라인
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);

  // Web Audio 관련 refs
  const audioRef = useRef(null);
  const [audioContext, setAudioContext] = useState(null);
  const mediaStreamRef = useRef(null);
  const sourceNodeRef = useRef(null);
  const compressorRef = useRef(null);
  const inputAnalyserRef = useRef(null);
  const outputAnalyserRef = useRef(null);
  const makeupGainRef = useRef(null);
  const wetGainRef = useRef(null);
  const dryGainRef = useRef(null);
  const outputVolumeNodeRef = useRef(null);

  // 그래프 refs
  const transferCanvasRef = useRef(null);
  const levelMeterCanvasRef = useRef(null);
  const timeGraphCanvasRef = useRef(null);

  // ring buffer for 시간 그래프
  const BUFFER_SIZE = 512;
  const inputBufferRef = useRef(new Float32Array(BUFFER_SIZE));
  const outputBufferRef = useRef(new Float32Array(BUFFER_SIZE));
  const compressionBufferRef = useRef(new Float32Array(BUFFER_SIZE));
  const bufferIndexRef = useRef(0);

  // 세번째 그래프에 표시할 선(Line)들의 표시 여부 체크박스
  const [showInputLine, setShowInputLine] = useState(true);
  const [showOutputLine, setShowOutputLine] = useState(true);
  const [showCompressionLine, setShowCompressionLine] = useState(true);

  // Offline Rendering
  const [isProcessing, setIsProcessing] = useState(false);
  const [downloadUrl, setDownloadUrl] = useState(null);

  // 사이드 패널 표시 여부
  const [isPanelOpen, setIsPanelOpen] = useState(false);

  // 프리셋 선택
  const [selectedPreset, setSelectedPreset] = useState("Flat (No Compression)");
  const handlePresetChange = (e) => {
    const presetName = e.target.value;
    setSelectedPreset(presetName);
    const preset = COMP_PRESETS[presetName];
    if (preset) {
      setAttack(preset.attack);
      setHold(preset.hold);
      setRelease(preset.release);
      setRatio(preset.ratio);
      setThreshold(preset.threshold);
      setKnee(preset.knee);
      setGain(preset.gain);
      setMix(preset.mix);
    }
  };

  // 파일 업로드
  const handleFileChange = (e) => {
    if (e.target.files.length > 0) {
      const file = e.target.files[0];
      const url = URL.createObjectURL(file);
      setAudioFile(url);
      setDownloadUrl(null);
    }
  };

  // Offline Rendering -> Download
  const handleDownloadCompressed = async () => {
    if (!audioFile) {
      alert("No file loaded");
      return;
    }
    setIsProcessing(true);
    setDownloadUrl(null);
    try {
      const buf = await Tone.Buffer.fromUrl(audioFile);
      const audioDur = buf.duration;
      const rendered = await Tone.Offline(() => {
        const player = new Tone.Player(buf).toDestination();
        const comp = new Tone.Compressor({
          attack: attack / 1000,
          release: release / 1000,
          ratio,
          threshold,
          knee,
        }).toDestination();
        const mg = new Tone.Gain(dbToGain(gain));
        const wGain = new Tone.Gain(mix / 100);
        const dGain = new Tone.Gain(1 - mix / 100);
        player.fan(dGain, comp);
        comp.connect(mg);
        mg.connect(wGain);
        const finalMix = new Tone.Gain();
        dGain.connect(finalMix);
        wGain.connect(finalMix);
        finalMix.toDestination();
        player.start(0);
      }, audioDur);
      const wavBlob = bufferToWave(rendered);
      const url = URL.createObjectURL(wavBlob);
      setDownloadUrl(url);
    } catch (err) {
      console.error(err);
      alert("Fail to create compressed file.");
    }
    setIsProcessing(false);
  };

  // 최신 그래프 파라미터들을 담는 ref
  const graphParamsRef = useRef({ threshold, ratio, knee, gain });
  useEffect(() => {
    graphParamsRef.current = { threshold, ratio, knee, gain };
  }, [threshold, ratio, knee, gain]);

  // 오디오 재생 종료 시 처리
  useEffect(() => {
    const audioEl = audioRef.current;
    if (audioEl) {
      const handleEnded = () => {
        audioEl.currentTime = 0;
        setIsPlaying(false);
      };
      audioEl.addEventListener("ended", handleEnded);
      return () => {
        audioEl.removeEventListener("ended", handleEnded);
      };
    }
  }, []);

  /** Play / Stop */
  const handlePlay = async () => {
    await Tone.start();
    if (isPlaying) return;
    if (inputSource === "audioFile") {
      if (!audioFile) {
        alert("No audio file selected");
        return;
      }
      if (!audioRef.current) return;
      if (audioRef.current.ended) {
        audioRef.current.currentTime = 0;
      }
      audioRef.current.src = audioFile;
      audioRef.current.volume = volume;
      audioRef.current.play();
      setIsPlaying(true);
      if (!audioContext) {
        const ac = new (window.AudioContext || window.webkitAudioContext)();
        setAudioContext(ac);
        sourceNodeRef.current = ac.createMediaElementSource(audioRef.current);
        const inA = ac.createAnalyser();
        inA.fftSize = 1024;
        inputAnalyserRef.current = inA;
        const comp = ac.createDynamicsCompressor();
        compressorRef.current = comp;
        const mg = ac.createGain();
        makeupGainRef.current = mg;
        const wG = ac.createGain();
        wetGainRef.current = wG;
        const dG = ac.createGain();
        dryGainRef.current = dG;
        outputVolumeNodeRef.current = null; // 파일 모드
        const outA = ac.createAnalyser();
        outA.fftSize = 1024;
        // <-- 수정: Analyser 노드의 dB 범위 설정
        outA.minDecibels = -60;
        outA.maxDecibels = 0;
        outputAnalyserRef.current = outA;
        sourceNodeRef.current.connect(inA);
        inA.connect(dG);
        inA.connect(comp);
        comp.connect(mg);
        mg.connect(wG);
        const finalMix = ac.createGain();
        dG.connect(finalMix);
        wG.connect(finalMix);
        finalMix.connect(outA);
        outA.connect(ac.destination);
      }
    } else if (inputSource === "usb" || inputSource === "laptop") {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;
        const ac = new (window.AudioContext || window.webkitAudioContext)();
        setAudioContext(ac);
        sourceNodeRef.current = ac.createMediaStreamSource(stream);
        const inA = ac.createAnalyser();
        inA.fftSize = 1024;
        inputAnalyserRef.current = inA;
        const comp = ac.createDynamicsCompressor();
        compressorRef.current = comp;
        const mg = ac.createGain();
        makeupGainRef.current = mg;
        const wG = ac.createGain();
        wetGainRef.current = wG;
        const dG = ac.createGain();
        dryGainRef.current = dG;
        const outVol = ac.createGain();
        outVol.gain.value = volume;
        outputVolumeNodeRef.current = outVol;
        const outA = ac.createAnalyser();
        outA.fftSize = 1024;
        // <-- 수정: Analyser 노드의 dB 범위 설정
        outA.minDecibels = -60;
        outA.maxDecibels = 0;
        outputAnalyserRef.current = outA;
        sourceNodeRef.current.connect(inA);
        inA.connect(dG);
        inA.connect(comp);
        comp.connect(mg);
        mg.connect(wG);
        const finalMix = ac.createGain();
        dG.connect(finalMix);
        wG.connect(finalMix);
        finalMix.connect(outVol);
        outVol.connect(outA);
        outA.connect(ac.destination);
        setIsPlaying(true);
      } catch (err) {
        console.error("Mic error:", err);
        alert("Mic/USB input failed or not permitted.");
      }
    }
  };

  const handleStop = () => {
    if (inputSource === "audioFile") {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
      }
    } else {
      if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach((track) => track.stop());
        mediaStreamRef.current = null;
      }
    }
    setIsPlaying(false);
  };

  /** 컴프레서 파라미터 -> Node 업데이트 */
  useEffect(() => {
    if (!compressorRef.current) return;
    compressorRef.current.attack.value = attack / 1000;
    compressorRef.current.release.value = release / 1000;
    compressorRef.current.ratio.value = ratio;
    compressorRef.current.threshold.value = threshold;
    compressorRef.current.knee.value = knee;
  }, [attack, hold, release, ratio, threshold, knee]);

  useEffect(() => {
    if (!makeupGainRef.current || !wetGainRef.current || !dryGainRef.current) return;
    makeupGainRef.current.gain.value = dbToGain(gain);
    wetGainRef.current.gain.value = mix / 100;
    dryGainRef.current.gain.value = 1 - mix / 100;
  }, [gain, mix]);

  /** volume -> <audio> element or outputVolumeNode */
  useEffect(() => {
    if (inputSource === "audioFile" && audioRef.current) {
      audioRef.current.volume = volume;
    } else if ((inputSource === "usb" || inputSource === "laptop") && outputVolumeNodeRef.current) {
      outputVolumeNodeRef.current.gain.value = volume;
    }
  }, [volume, inputSource]);

  /** timeline update */
  useEffect(() => {
    const onTimeUpdate = () => {
      if (audioRef.current) {
        setCurrentTime(audioRef.current.currentTime);
        setDuration(audioRef.current.duration || 0);
      }
    };
    if (audioRef.current) {
      audioRef.current.addEventListener("timeupdate", onTimeUpdate);
    }
    return () => {
      if (audioRef.current) {
        audioRef.current.removeEventListener("timeupdate", onTimeUpdate);
      }
    };
  }, []);

  const handleSeek = (e) => {
    if (audioRef.current) {
      audioRef.current.currentTime = +e.target.value;
    }
  };

  /** 첫 번째 그래프: X32 스타일 컴프레서 곡선 */
  function drawX32CompressorCurve() {
    const canvas = transferCanvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const cw = canvas.clientWidth;
    const ch = canvas.clientHeight;
    canvas.width = cw * dpr;
    canvas.height = ch * dpr;
    const ctx = canvas.getContext("2d");
    ctx.scale(dpr, dpr);
    ctx.clearRect(0, 0, cw, ch);
    ctx.fillStyle = "#000";
    ctx.fillRect(0, 0, cw, ch);

    // 그리드 그리기
    ctx.strokeStyle = "#444";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let i = -60; i <= 0; i += 10) {
      const x = ((i + 60) / 60) * cw;
      ctx.moveTo(x, 0);
      ctx.lineTo(x, ch);
    }
    for (let j = -60; j <= 0; j += 10) {
      const y = ch - (((j + 60) / 60) * ch);
      ctx.moveTo(0, y);
      ctx.lineTo(cw, y);
    }
    ctx.stroke();

    // 축 레이블
    ctx.fillStyle = "#fff";
    ctx.font = "10px sans-serif";
    ctx.textAlign = "center";
    for (let i = -60; i <= 0; i += 20) {
      const x = ((i + 60) / 60) * cw;
      ctx.fillText(`${i}`, x, ch - 2);
    }
    ctx.textAlign = "right";
    for (let j = -60; j <= 0; j += 20) {
      const y = ch - (((j + 60) / 60) * ch);
      ctx.fillText(`${j}`, cw - 2, y);
    }

    const { threshold, ratio, knee, gain } = graphParamsRef.current;
    function compTransfer(inDb) {
      if (knee === 0) {
        if (inDb < threshold) {
          return inDb + gain;
        } else {
          const diff = inDb - threshold;
          return threshold + diff / ratio + gain;
        }
      } else {
        const halfK = knee;
        const start = threshold - halfK;
        const end = threshold + halfK;
        if (inDb < start) {
          return inDb + gain;
        } else if (inDb > end) {
          const diff = inDb - threshold;
          return threshold + diff / ratio + gain;
        } else {
          const frac = (inDb - start) / (end - start);
          const before = inDb;
          const after = threshold + (inDb - threshold) / ratio;
          const smooth = frac * frac * (3 - 2 * frac);
          return before + (after - before) * smooth + gain;
        }
      }
    }

    ctx.strokeStyle = "#0f0";
    ctx.lineWidth = 2;
    ctx.beginPath();
    let first = true;
    for (let inDb = -60; inDb <= 0; inDb++) {
      const x = ((inDb + 60) / 60) * cw;
      const outDb = compTransfer(inDb);
      const clipped = Math.max(-60, Math.min(0, outDb));
      const y = ch - (((clipped + 60) / 60) * ch);
      if (first) {
        ctx.moveTo(x, y);
        first = false;
      } else {
        ctx.lineTo(x, y);
      }
    }
    ctx.stroke();
    ctx.lineTo(cw, ch);
    ctx.lineTo(0, ch);
    ctx.closePath();
    ctx.fillStyle = "rgba(0,255,0,0.2)";
    ctx.fill();

    const thrX = ((threshold + 60) / 60) * cw;
    const thrY = ch - (((threshold + 60) / 60) * ch);
    ctx.fillStyle = "#fff";
    ctx.beginPath();
    ctx.arc(thrX, thrY, 4, 0, Math.PI * 2);
    ctx.fill();
  }

  /** 두 번째 그래프: 레벨 미터 (색상 구간 적용) */
  function drawLevelMeter() {
    const canvas = levelMeterCanvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    // fallback 사이즈 지정 (clientWidth/clientHeight가 0인 경우)
    const cw = canvas.clientWidth || 500;
    const ch = canvas.clientHeight || 10;
    canvas.width = cw * dpr;
    canvas.height = ch * dpr;
    const ctx = canvas.getContext("2d");
    ctx.scale(dpr, dpr);
    ctx.clearRect(0, 0, cw, ch);
    ctx.fillStyle = "#000";
    ctx.fillRect(0, 0, cw, ch);

    let dBVal = -60;
    if (outputAnalyserRef.current) {
      dBVal = measureAnalyserDb(outputAnalyserRef.current, -60, 0);
    }
    const range = 60;
    const frac = (dBVal + 60) / range;
    const barHeight = frac * ch;
    let fillColor = "green";
    if (dBVal > -20 && dBVal <= -10) {
      fillColor = "yellow";
    } else if (dBVal > -10) {
      fillColor = "red";
    }
    ctx.fillStyle = fillColor;
    ctx.fillRect(0, ch - barHeight, cw, barHeight);

    ctx.strokeStyle = "#444";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let i = -60; i <= 0; i += 10) {
      const y = ch - (((i + 60) / range) * ch);
      ctx.moveTo(0, y);
      ctx.lineTo(cw, y);
    }
    ctx.stroke();

    ctx.fillStyle = "#fff";
    ctx.font = "10px sans-serif";
    ctx.textAlign = "left";
    for (let i = -60; i <= 0; i += 10) {
      const y = ch - (((i + 60) / range) * ch);
      ctx.fillText(`${i}`, 2, y + 4);
    }
  }

  function measureAnalyserDb(analyser, minDb = -60, maxDb = 0) {
    const data = new Float32Array(analyser.fftSize);
    analyser.getFloatTimeDomainData(data);
    let sum = 0;
    for (let i = 0; i < data.length; i++) {
      sum += data[i] * data[i];
    }
    const rms = Math.sqrt(sum / data.length);
    let valDb = 20 * Math.log10(rms);
    if (!isFinite(valDb)) valDb = -100;
    if (valDb < minDb) valDb = minDb;
    if (valDb > maxDb) valDb = maxDb;
    return valDb;
  }

  /** 세 번째 그래프: 시간축 dB */
  function drawTimeGraph() {
    const canvas = timeGraphCanvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const cw = canvas.clientWidth;
    const ch = canvas.clientHeight;
    canvas.width = cw * dpr;
    canvas.height = ch * dpr;
    const ctx = canvas.getContext("2d");
    ctx.scale(dpr, dpr);
    ctx.clearRect(0, 0, cw, ch);
    ctx.fillStyle = "#1c1c3a";
    ctx.fillRect(0, 0, cw, ch);

    ctx.strokeStyle = "#444";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let i = -30; i <= 0; i += 5) {
      const frac = (i + 30) / 30;
      const y = (1 - frac) * ch;
      ctx.moveTo(0, y);
      ctx.lineTo(cw, y);
    }
    ctx.stroke();

    ctx.fillStyle = "#fff";
    ctx.font = "10px sans-serif";
    ctx.textAlign = "left";
    for (let i = -30; i <= 0; i += 10) {
      const frac = (i + 30) / 30;
      const y = (1 - frac) * ch;
      ctx.fillText(`${i} dB`, 2, y);
    }

    function drawLine(buffer, color, show) {
      if (!show) return;
      ctx.strokeStyle = color;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      for (let i = 0; i < BUFFER_SIZE; i++) {
        const idx = (bufferIndexRef.current + i) % BUFFER_SIZE;
        const val = buffer[idx];
        const frac = (val + 30) / 30;
        const x = (i / (BUFFER_SIZE - 1)) * cw;
        const y = (1 - frac) * ch;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.stroke();
    }
    drawLine(inputBufferRef.current, "#fff", showInputLine);
    drawLine(outputBufferRef.current, "#ffdf55", showOutputLine);
    drawLine(compressionBufferRef.current, "#bb55ff", showCompressionLine);
  }

  // 애니메이션 루프: 그래프 계속 갱신
  useEffect(() => {
    let reqId;
    function animate() {
      drawX32CompressorCurve();
      drawLevelMeter();
      drawTimeGraph();
      reqId = requestAnimationFrame(animate);
    }
    animate();
    return () => cancelAnimationFrame(reqId);
  }, []);

  // ring buffer 업데이트 (50ms)
  useEffect(() => {
    let timerId;
    function sampleLoop() {
      if (isPlaying) {
        let inDb = -30;
        let outDb = -30;
        if (inputAnalyserRef.current) {
          inDb = measureAnalyserDb(inputAnalyserRef.current, -30, 0);
        }
        if (outputAnalyserRef.current) {
          outDb = measureAnalyserDb(outputAnalyserRef.current, -30, 0);
        }
        const compDb = inDb - outDb;
        const idx = bufferIndexRef.current;
        inputBufferRef.current[idx] = inDb;
        outputBufferRef.current[idx] = outDb;
        compressionBufferRef.current[idx] = compDb;
        bufferIndexRef.current = (idx + 1) % BUFFER_SIZE;
      }
      timerId = setTimeout(sampleLoop, 50);
    }
    sampleLoop();
    return () => clearTimeout(timerId);
  }, [isPlaying]);

  const handleResetAll = () => {
    setAttack(DEFAULT_PARAMS.attack);
    setHold(DEFAULT_PARAMS.hold);
    setRelease(DEFAULT_PARAMS.release);
    setRatio(DEFAULT_PARAMS.ratio);
    setThreshold(DEFAULT_PARAMS.threshold);
    setKnee(DEFAULT_PARAMS.knee);
    setGain(DEFAULT_PARAMS.gain);
    setMix(DEFAULT_PARAMS.mix);
  };

  const togglePanel = () => {
    setIsPanelOpen(!isPanelOpen);
  };

  return (
    <div className="comp-container">
      <button className="comp-toggle-panel-btn" onClick={togglePanel}>
        {isPanelOpen ? "Close Panel" : "Open Panel"}
      </button>

      <div className="comp-top-section">
        <div className="comp-graphs">
          <div className="comp-graph1">
            <canvas ref={transferCanvasRef} className="comp-transfer-canvas" />
          </div>
          <div className="comp-graph2">
            <canvas ref={levelMeterCanvasRef} className="comp-level-meter-canvas" />
          </div>
        </div>
        <div className="comp-params">
          <h3>Compressor Params</h3>
          <div className="comp-preset-row">
            <label>Preset:</label>
            <select value={selectedPreset} onChange={handlePresetChange}>
              {Object.keys(COMP_PRESETS).map((name) => (
                <option key={name} value={name}>
                  {name}
                </option>
              ))}
            </select>
          </div>
          <div className="comp-param-row">
            <label>Attack (ms): </label>
            <input
              type="number"
              value={attack}
              onChange={(e) => {
                const val = e.target.value;
                setAttack(val === "" ? DEFAULT_PARAMS.attack : Number(val));
              }}
            />
            <input type="range" min="0" max="200" step="1" value={attack} onChange={(e) => setAttack(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Hold (ms): </label>
            <input
              type="number"
              value={hold}
              onChange={(e) => {
                const val = e.target.value;
                setHold(val === "" ? DEFAULT_PARAMS.hold : Number(val));
              }}
            />
            <input type="range" min="0" max="2000" step="1" value={hold} onChange={(e) => setHold(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Release (ms): </label>
            <input
              type="number"
              value={release}
              onChange={(e) => {
                const val = e.target.value;
                setRelease(val === "" ? DEFAULT_PARAMS.release : Number(val));
              }}
            />
            <input type="range" min="5" max="4000" step="1" value={release} onChange={(e) => setRelease(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Ratio: </label>
            <input
              type="number"
              value={ratio}
              onChange={(e) => {
                const val = e.target.value;
                setRatio(val === "" ? DEFAULT_PARAMS.ratio : Number(val));
              }}
            />
            <input type="range" min="1.1" max="20" step="0.1" value={ratio} onChange={(e) => setRatio(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Threshold (dB): </label>
            <input
              type="number"
              value={threshold}
              onChange={(e) => {
                const val = e.target.value;
                setThreshold(val === "" ? DEFAULT_PARAMS.threshold : Number(val));
              }}
            />
            <input type="range" min="-60" max="0" step="1" value={threshold} onChange={(e) => setThreshold(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Knee (dB): </label>
            <input
              type="number"
              value={knee}
              onChange={(e) => {
                const val = e.target.value;
                setKnee(val === "" ? DEFAULT_PARAMS.knee : Number(val));
              }}
            />
            <input type="range" min="0" max="10" step="0.1" value={knee} onChange={(e) => setKnee(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Gain (dB): </label>
            <input
              type="number"
              value={gain}
              onChange={(e) => {
                const val = e.target.value;
                setGain(val === "" ? DEFAULT_PARAMS.gain : Number(val));
              }}
            />
            <input type="range" min="-12" max="12" step="0.5" value={gain} onChange={(e) => setGain(Number(e.target.value))} />
          </div>
          <div className="comp-param-row">
            <label>Mix (%): </label>
            <input
              type="number"
              value={mix}
              onChange={(e) => {
                const val = e.target.value;
                setMix(val === "" ? DEFAULT_PARAMS.mix : Number(val));
              }}
            />
            <input type="range" min="0" max="100" step="1" value={mix} onChange={(e) => setMix(Number(e.target.value))} />
          </div>
          <button className="comp-reset-btn" onClick={handleResetAll}>
            Reset All
          </button>
        </div>
      </div>

      <div className="comp-bottom-section">
        <h3>Time-based dB Graph (-30dB ~ 0dB)</h3>
        <div className="comp-timegraph-options">
          <label>
            <input type="checkbox" checked={showInputLine} onChange={(e) => setShowInputLine(e.target.checked)} />
            입력(White)
          </label>
          <label>
            <input type="checkbox" checked={showOutputLine} onChange={(e) => setShowOutputLine(e.target.checked)} />
            출력(Yellow)
          </label>
          <label>
            <input type="checkbox" checked={showCompressionLine} onChange={(e) => setShowCompressionLine(e.target.checked)} />
            실제 컴프레셔(Purple)
          </label>
        </div>
        <canvas ref={timeGraphCanvasRef} className="comp-timegraph-canvas" />
      </div>

      <div className={`comp-side-panel ${isPanelOpen ? "comp-panel-open" : ""}`}>
        <div className="comp-panel-content">
          <h3>Audio I/O</h3>
          <div className="comp-panel-row">
            <label>Input Source: </label>
            <select value={inputSource} onChange={(e) => setInputSource(e.target.value)}>
              <option value="audioFile">Audio File</option>
              <option value="usb">USB Input</option>
              <option value="laptop">Laptop Mic</option>
            </select>
          </div>
          {inputSource === "audioFile" && (
            <>
              <div className="comp-panel-row">
                <label>File: </label>
                <input type="file" accept="audio/*" onChange={handleFileChange} />
              </div>
              <audio ref={audioRef} style={{ display: "none" }} />
              {audioFile && (
                <div className="comp-panel-row">
                  <label>Timeline: </label>
                  <input
                    type="range"
                    min={0}
                    max={duration}
                    step="0.01"
                    value={currentTime}
                    onChange={(e) => {
                      setCurrentTime(+e.target.value);
                      handleSeek(e);
                    }}
                  />
                  <span>
                    {currentTime.toFixed(1)}/{duration.toFixed(1)}
                  </span>
                </div>
              )}
            </>
          )}
          <div className="comp-panel-row">
            <label>Volume: </label>
            <input type="range" min="0" max="1" step="0.01" value={volume} onChange={(e) => setVolume(+e.target.value)} />
            <span>{(volume * 100).toFixed(0)}%</span>
          </div>
          <div className="comp-panel-row">
            <button onClick={handlePlay}>Play</button>
            <button onClick={handleStop}>Stop</button>
          </div>
          {inputSource === "audioFile" && (
            <div className="comp-panel-row">
              <h4>Offline Compress</h4>
              <button onClick={handleDownloadCompressed} disabled={!audioFile || isProcessing}>
                {isProcessing ? "Processing..." : "Generate & Download WAV"}
              </button>
              {downloadUrl && (
                <div>
                  <a href={downloadUrl} download="compressed.wav">
                    [Download File]
                  </a>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Comp;
