import React, { useState, useEffect, useRef } from "react";
import * as Tone from "tone";
import "./noise.css";

const Noise = () => {
  // 오디오 입력 소스 선택: "file", "mic", "usb"
  const [inputSource, setInputSource] = useState("file");
  const [isPlaying, setIsPlaying] = useState(false);
  const [player, setPlayer] = useState(null);
  const [mic, setMic] = useState(null);
  const [volumeValue, setVolumeValue] = useState(0);
  const [panValue, setPanValue] = useState(0);
  // 노이즈 제거 효과: 하이패스 필터의 컷오프 주파수 (낮은 주파수를 제거)
  const [noiseReductionValue, setNoiseReductionValue] = useState(80);

  // Tone.js 노드들을 참조하기 위한 useRef
  const volumeNodeRef = useRef(null);
  const pannerRef = useRef(null);
  const filterRef = useRef(null);
  const analyserRef = useRef(null);

  // 시각화용 캔버스 ref
  const canvasRef = useRef(null);

  // 컴포넌트 마운트 시 Tone.js 효과 체인 초기화
  useEffect(() => {
    // 볼륨 노드 (dB 조절)
    volumeNodeRef.current = new Tone.Volume(volumeValue);
    // 패닝 노드 (좌우 조절)
    pannerRef.current = new Tone.Panner(panValue);
    // 하이패스 필터를 noise reduction 효과로 사용
    filterRef.current = new Tone.Filter(noiseReductionValue, "highpass");
    // 분석기: FFT 분석을 통해 실시간 스펙트럼 데이터 획득 (256 bin)
    analyserRef.current = new Tone.Analyser("fft", 256);
    // 노드 체인은 오디오 소스에 따라 연결됩니다.
  }, []);

  // 실시간 시각화를 위한 캔버스 업데이트 (애니메이션 루프)
  useEffect(() => {
    let animationId;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    const draw = () => {
      if (analyserRef.current) {
        const data = analyserRef.current.getValue(); // dB 단위의 배열 (일반적으로 음수 값)
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // x축: 주파수 bin, y축: dB 값을 변환한 막대 높이 (창의적으로 표현)
        const barWidth = canvas.width / data.length;
        for (let i = 0; i < data.length; i++) {
          // data[i]가 음수이므로 +140을 더해 양수화한 후 스케일링
          const barHeight = (data[i] + 140) * 2;
          ctx.fillStyle = `hsl(${(i / data.length) * 360}, 100%, 50%)`;
          ctx.fillRect(i * barWidth, canvas.height - barHeight, barWidth - 2, barHeight);
        }
      }
      animationId = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(animationId);
  }, []);

  // 오디오 파일 업로드 핸들러
  const handleFileUpload = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const arrayBuffer = e.target.result;
        Tone.context.decodeAudioData(arrayBuffer, (buffer) => {
          if (player) player.dispose();
          const newPlayer = new Tone.Player(buffer, () => {
            // 연결 체인: Player → Filter → Panner → Volume → Analyser → Destination
            newPlayer.chain(
              filterRef.current,
              pannerRef.current,
              volumeNodeRef.current,
              analyserRef.current,
              Tone.Destination
            );
            newPlayer.start();
            setIsPlaying(true);
          });
          setPlayer(newPlayer);
        });
      };
      reader.readAsArrayBuffer(file);
    }
  };

  // 마이크/USB 입력 핸들러
  const handleMicInput = async () => {
    try {
      const micStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const newMic = new Tone.UserMedia();
      await newMic.open();
      // 연결 체인: UserMedia → Filter → Panner → Volume → Analyser → Destination
      newMic.chain(
        filterRef.current,
        pannerRef.current,
        volumeNodeRef.current,
        analyserRef.current,
        Tone.Destination
      );
      setMic(newMic);
      setIsPlaying(true);
    } catch (err) {
      console.error("마이크 접근 오류:", err);
    }
  };

  // Play / Stop 토글 핸들러
  const togglePlay = () => {
    if (player) {
      if (isPlaying) {
        player.stop();
        setIsPlaying(false);
      } else {
        player.start();
        setIsPlaying(true);
      }
    } else if (mic) {
      console.log("마이크 입력은 실시간이므로 정지 기능은 별도 구현이 필요합니다.");
    }
  };

  // 볼륨 슬라이더 핸들러
  const handleVolumeChange = (e) => {
    const newVol = parseFloat(e.target.value);
    setVolumeValue(newVol);
    if (volumeNodeRef.current) volumeNodeRef.current.volume.value = newVol;
  };

  // 패닝 슬라이더 핸들러
  const handlePanChange = (e) => {
    const newPan = parseFloat(e.target.value);
    setPanValue(newPan);
    if (pannerRef.current) pannerRef.current.pan.value = newPan;
  };

  // 노이즈 제거(하이패스 필터) 슬라이더 핸들러
  const handleNoiseReductionChange = (e) => {
    const newValue = parseFloat(e.target.value);
    setNoiseReductionValue(newValue);
    if (filterRef.current) filterRef.current.frequency.value = newValue;
  };

  // 다운로드 핸들러 (이펙트 적용된 오디오 다운로드 - stub 처리)
  const handleDownload = () => {
    console.log("다운로드: 이펙트 적용 오디오 파일 다운로드 (기능 구현 필요)");
    // Tone.Offline 등을 활용해 오디오 렌더링 후 Blob 생성 로직을 추가할 수 있습니다.
  };

  return (
    <div className="noise-container">
      <h2>Noise Removal Program</h2>
      
      {/* 오디오 입력 소스 선택 */}
      <div className="input-source">
        <label>
          <input
            type="radio"
            name="inputSource"
            value="file"
            checked={inputSource === "file"}
            onChange={(e) => setInputSource(e.target.value)}
          />
          Audio File
        </label>
        <label>
          <input
            type="radio"
            name="inputSource"
            value="mic"
            checked={inputSource === "mic"}
            onChange={(e) => setInputSource(e.target.value)}
          />
          Laptop Mic
        </label>
        <label>
          <input
            type="radio"
            name="inputSource"
            value="usb"
            checked={inputSource === "usb"}
            onChange={(e) => setInputSource(e.target.value)}
          />
          USB Input
        </label>
      </div>

      {/* 오디오 소스 입력 컨트롤 */}
      {inputSource === "file" && (
        <div className="file-upload">
          <input type="file" accept="audio/*" onChange={handleFileUpload} />
        </div>
      )}
      {(inputSource === "mic" || inputSource === "usb") && (
        <div className="mic-input">
          <button onClick={handleMicInput}>Start Mic Input</button>
        </div>
      )}
      
      {/* 재생 / 정지 버튼 */}
      <div className="playback-control">
        <button onClick={togglePlay}>{isPlaying ? "Stop" : "Play"}</button>
      </div>

      {/* 볼륨 및 패닝 컨트롤 */}
      <div className="slider-control">
        <label>Volume (dB): </label>
        <input
          type="range"
          min="-60"
          max="0"
          step="1"
          value={volumeValue}
          onChange={handleVolumeChange}
        />
        <span>{volumeValue} dB</span>
      </div>
      <div className="slider-control">
        <label>Panning (L-R): </label>
        <input
          type="range"
          min="-1"
          max="1"
          step="0.01"
          value={panValue}
          onChange={handlePanChange}
        />
        <span>{panValue}</span>
      </div>

      {/* 노이즈 제거 컨트롤 (하이패스 필터 컷오프 주파수) */}
      <div className="slider-control">
        <label>Noise Reduction Frequency (Hz): </label>
        <input
          type="range"
          min="20"
          max="200"
          step="1"
          value={noiseReductionValue}
          onChange={handleNoiseReductionChange}
        />
        <span>{noiseReductionValue} Hz</span>
      </div>

      {/* 다운로드 버튼 */}
      <div className="download-control">
        <button onClick={handleDownload}>Download Processed Audio</button>
      </div>

      {/* 노이즈/스펙트럼 시각화 영역 */}
      <div className="visualization-container">
        <canvas ref={canvasRef} width="800" height="300" className="noise-canvas"></canvas>
      </div>
    </div>
  );
};

export default Noise;
